import { hasPermissionCode } from '../utils/erpPermissionCode';

const PREFIX = 'erp-supply:purchasing:einvoices';

export function useHddtPermissions() {
  const canVerify =
    hasPermissionCode(`${PREFIX}:verify`) ||
    hasPermissionCode(`${PREFIX}:write`);
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canVerify,
  };
}
